import math

PI = 3.1415926535

def realcompare(a: float, b: float) -> str:
    if math.isclose(a, b, rel_tol=1e-6, abs_tol=1e-6):
        return "EQ"
    elif a < b:
        return "LT"
    else:
        return "GT"

def decide(numpoints: int, x: list, y: list, parameters: dict, lcm: list, pum_diag: list):
    def dist(x1, y1, x2, y2):
        return math.hypot(x1 - x2, y1 - y2)

    def get_area(x1, y1, x2, y2, x3, y3):
        return 0.5 * abs(x1*(y2 - y3) + x2*(y3 - y1) + x3*(y1 - y2))

    def can_contain_in_circle(x1, y1, x2, y2, x3, y3, radius):
        a = dist(x1, y1, x2, y2)
        b = dist(x2, y2, x3, y3)
        c = dist(x3, y3, x1, y1)
        a, b, c = sorted([a, b, c])

        if realcompare(c**2, a**2 + b**2) in ("GT", "EQ"):
            min_rad = c / 2.0
        else:
            area = get_area(x1, y1, x2, y2, x3, y3)
            if realcompare(area, 0.0) == "EQ":
                min_rad = c / 2.0
            else:
                min_rad = (a * b * c) / (4.0 * area)

        if realcompare(min_rad, radius) == "GT":
            return False
        return True

    def check_angle(x1, y1, x2, y2, x3, y3, epsilon):
        if (realcompare(x1, x2) == "EQ" and realcompare(y1, y2) == "EQ") or \
           (realcompare(x3, x2) == "EQ" and realcompare(y3, y2) == "EQ"):
            return False

        v1x, v1y = x1 - x2, y1 - y2
        v2x, v2y = x3 - x2, y3 - y2
        ang = math.atan2(v2y, v2x) - math.atan2(v1y, v1x)
        if ang < 0:
            ang += 2 * PI

        if realcompare(ang, PI - epsilon) == "LT" or realcompare(ang, PI + epsilon) == "GT":
            return True
        return False

    def get_quadrant(px, py):
        x_comp = realcompare(px, 0.0)
        y_comp = realcompare(py, 0.0)
        if x_comp in ("GT", "EQ") and y_comp in ("GT", "EQ"):
            return 1
        if x_comp == "LT" and y_comp in ("GT", "EQ"):
            return 2
        if x_comp in ("LT", "EQ") and y_comp == "LT":
            return 3
        if x_comp == "GT" and y_comp == "LT":
            return 4

    cmv = [False] * 15

    # CMV 0 (LIC 1)
    for i in range(numpoints - 1):
        if realcompare(dist(x[i], y[i], x[i+1], y[i+1]), parameters["LENGTH1"]) == "GT":
            cmv[0] = True
            break

    # CMV 1 (LIC 2)
    for i in range(numpoints - 2):
        if not can_contain_in_circle(x[i], y[i], x[i+1], y[i+1], x[i+2], y[i+2], parameters["RADIUS1"]):
            cmv[1] = True
            break

    # CMV 2 (LIC 3)
    for i in range(numpoints - 2):
        if check_angle(x[i], y[i], x[i+1], y[i+1], x[i+2], y[i+2], parameters["EPSILON"]):
            cmv[2] = True
            break

    # CMV 3 (LIC 4)
    for i in range(numpoints - 2):
        area = get_area(x[i], y[i], x[i+1], y[i+1], x[i+2], y[i+2])
        if realcompare(area, parameters["AREA1"]) == "GT":
            cmv[3] = True
            break

    # CMV 4 (LIC 5)
    q_pts = parameters["Q_PTS"]
    quads = parameters["QUADS"]
    for i in range(numpoints - q_pts + 1):
        q_set = set()
        for j in range(i, i + q_pts):
            q_set.add(get_quadrant(x[j], y[j]))
        if len(q_set) > quads:
            cmv[4] = True
            break

    # CMV 5 (LIC 6)
    for i in range(numpoints - 1):
        if realcompare(x[i+1] - x[i], 0.0) == "LT":
            cmv[5] = True
            break

    # CMV 6 (LIC 7)
    if numpoints >= 3:
        n_pts = parameters["N_PTS"]
        dist_param = parameters["DIST"]
        for i in range(numpoints - n_pts + 1):
            first_x, first_y = x[i], y[i]
            last_x, last_y = x[i + n_pts - 1], y[i + n_pts - 1]
            is_identical = (realcompare(first_x, last_x) == "EQ" and realcompare(first_y, last_y) == "EQ")
            for j in range(i + 1, i + n_pts - 1):
                if is_identical:
                    d = dist(x[j], y[j], first_x, first_y)
                else:
                    A = last_y - first_y
                    B = -(last_x - first_x)
                    C = last_x * first_y - last_y * first_x
                    d = abs(A * x[j] + B * y[j] + C) / math.hypot(A, B)
                if realcompare(d, dist_param) == "GT":
                    cmv[6] = True
                    break
            if cmv[6]:
                break

    # CMV 7 (LIC 8)
    if numpoints >= 3:
        k_pts = parameters["K_PTS"]
        for i in range(numpoints - k_pts - 1):
            if realcompare(dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1]), parameters["LENGTH1"]) == "GT":
                cmv[7] = True
                break

    # CMV 8 (LIC 9)
    if numpoints >= 5:
        a_pts = parameters["A_PTS"]
        b_pts = parameters["B_PTS"]
        for i in range(numpoints - a_pts - b_pts - 2):
            p1, p2, p3 = i, i + a_pts + 1, i + a_pts + b_pts + 2
            if not can_contain_in_circle(x[p1], y[p1], x[p2], y[p2], x[p3], y[p3], parameters["RADIUS1"]):
                cmv[8] = True
                break

    # CMV 9 (LIC 10)
    if numpoints >= 5:
        c_pts = parameters["C_PTS"]
        d_pts = parameters["D_PTS"]
        for i in range(numpoints - c_pts - d_pts - 2):
            p1, p2, p3 = i, i + c_pts + 1, i + c_pts + d_pts + 2
            if check_angle(x[p1], y[p1], x[p2], y[p2], x[p3], y[p3], parameters["EPSILON"]):
                cmv[9] = True
                break

    # CMV 10 (LIC 11)
    if numpoints >= 5:
        e_pts = parameters["E_PTS"]
        f_pts = parameters["F_PTS"]
        for i in range(numpoints - e_pts - f_pts - 2):
            p1, p2, p3 = i, i + e_pts + 1, i + e_pts + f_pts + 2
            area = get_area(x[p1], y[p1], x[p2], y[p2], x[p3], y[p3])
            if realcompare(area, parameters["AREA1"]) == "GT":
                cmv[10] = True
                break

    # CMV 11 (LIC 12)
    if numpoints >= 3:
        g_pts = parameters["G_PTS"]
        for i in range(numpoints - g_pts - 1):
            j = i + g_pts + 1
            if realcompare(x[j] - x[i], 0.0) == "LT":
                cmv[11] = True
                break

    # CMV 12 (LIC 13)
    if numpoints >= 3:
        k_pts = parameters["K_PTS"]
        cond1 = False
        cond2 = False
        for i in range(numpoints - k_pts - 1):
            d = dist(x[i], y[i], x[i + k_pts + 1], y[i + k_pts + 1])
            if realcompare(d, parameters["LENGTH1"]) == "GT":
                cond1 = True
            if realcompare(d, parameters["LENGTH2"]) == "LT":
                cond2 = True
        cmv[12] = cond1 and cond2

    # CMV 13 (LIC 14)
    if numpoints >= 5:
        a_pts = parameters["A_PTS"]
        b_pts = parameters["B_PTS"]
        cond1 = False
        cond2 = False
        for i in range(numpoints - a_pts - b_pts - 2):
            p1, p2, p3 = i, i + a_pts + 1, i + a_pts + b_pts + 2
            if not can_contain_in_circle(x[p1], y[p1], x[p2], y[p2], x[p3], y[p3], parameters["RADIUS1"]):
                cond1 = True
            if can_contain_in_circle(x[p1], y[p1], x[p2], y[p2], x[p3], y[p3], parameters["RADIUS2"]):
                cond2 = True
        cmv[13] = cond1 and cond2

    # CMV 14 (LIC 15)
    if numpoints >= 5:
        e_pts = parameters["E_PTS"]
        f_pts = parameters["F_PTS"]
        cond1 = False
        cond2 = False
        for i in range(numpoints - e_pts - f_pts - 2):
            p1, p2, p3 = i, i + e_pts + 1, i + e_pts + f_pts + 2
            area = get_area(x[p1], y[p1], x[p2], y[p2], x[p3], y[p3])
            if realcompare(area, parameters["AREA1"]) == "GT":
                cond1 = True
            if realcompare(area, parameters["AREA2"]) == "LT":
                cond2 = True
        cmv[14] = cond1 and cond2

    # Construct PUM
    pum = [[False]*15 for _ in range(15)]
    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = pum_diag[i]
            else:
                op = lcm[i][j]
                if op == "NOTUSED":
                    pum[i][j] = True
                elif op == "ANDD":
                    pum[i][j] = cmv[i] and cmv[j]
                elif op == "ORR":
                    pum[i][j] = cmv[i] or cmv[j]

    # Construct FUV
    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            fuv[i] = True
        else:
            fuv[i] = all(pum[i])

    # Launch Decision
    launch = all(fuv)

    return cmv, pum, fuv, launch
